function CertificationManager({ onUpdate }: { onUpdate: () => void }) {
  const [items, setItems] = useState<any[]>([])
  const [editingId, setEditingId] = useState<string | null>(null)
  const emptyForm = { title: "", issuer: "", date: "", link: "", imageUrl: "" }
  const [form, setForm] = useState(emptyForm)

  useEffect(() => { loadItems() }, [])
  const loadItems = async () => setItems(await (await fetch("/api/certifications")).json())
  
  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault()
    const url = editingId ? `/api/certifications/${editingId}` : "/api/certifications"
    const method = editingId ? "PUT" : "POST"
    await fetch(url, { method, headers: { "Content-Type": "application/json" }, body: JSON.stringify(form) })
    setForm(emptyForm); setEditingId(null); loadItems(); onUpdate()
  }

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if(!file) return
    const reader = new FileReader()
    reader.onload = (ev) => {
      setForm({...form, imageUrl: ev.target?.result as string})
    }
    reader.readAsDataURL(file)
  }

  const handleEdit = (item: any) => { setEditingId(item._id); setForm({ title: item.title||"", issuer: item.issuer||"", date: item.date||"", link: item.link||"", imageUrl: item.imageUrl||"" }); window.scrollTo({ top: 0, behavior: 'smooth' }) }
  const handleDelete = async (id: string) => { if(confirm("Delete?")){ await fetch(`/api/certifications/${id}`, { method: "DELETE" }); loadItems(); onUpdate() } }

  return (
    <div className="space-y-8 animate-in fade-in">
      <Card>
        <CardHeader><CardTitle className="flex justify-between items-center">{editingId ? "Edit Certification" : "Add Certification"} {editingId && <Button variant="ghost" onClick={() => {setEditingId(null); setForm(emptyForm)}}>Cancel</Button>}</CardTitle></CardHeader>
        <CardContent>
          <form onSubmit={handleSave} className="space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <Input placeholder="Certification Name" value={form.title} onChange={e=>setForm({...form, title: e.target.value})} required />
              <Input placeholder="Issuer (e.g. AWS, Coursera)" value={form.issuer} onChange={e=>setForm({...form, issuer: e.target.value})} required />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <Input placeholder="Date (e.g. Oct 2025)" value={form.date} onChange={e=>setForm({...form, date: e.target.value})} required />
              <Input placeholder="Credential URL (Optional)" value={form.link} onChange={e=>setForm({...form, link: e.target.value})} />
            </div>
            <div className="space-y-2">
              <Label>Upload Certificate Image (Optional)</Label>
              <Input type="file" accept="image/*" onChange={handleImageUpload} />
              {form.imageUrl && <img src={form.imageUrl} alt="preview" className="h-20 object-contain rounded border border-border/50" />}
            </div>
            <Button type="submit">{editingId ? "Update" : "Save"}</Button>
          </form>
        </CardContent>
      </Card>
      <div className="grid gap-4">
        {items.map(i => (
          <Card key={i._id} className="flex justify-between items-center p-4">
            <div className="flex items-center gap-4">
              {i.imageUrl && <img src={i.imageUrl} className="w-12 h-12 object-cover rounded" alt="cert" />}
              <div><h3 className="font-bold">{i.title}</h3><p className="text-sm">{i.issuer} ({i.date})</p></div>
            </div>
            <div className="flex gap-2">
              <Button variant="ghost" size="icon" onClick={() => handleEdit(i)}><Edit className="w-4 h-4" /></Button>
              <Button variant="ghost" size="icon" onClick={() => handleDelete(i._id)}><Trash2 className="w-4 h-4 text-destructive" /></Button>
            </div>
          </Card>
        ))}
      </div>
    </div>
  )
}
